using BuildingBlocks.Charts;using SharedKernel;namespace DashboardCharts.Domain;/** <summary>Chart type.</summary> */ public enum ChartType{Bar,Pie,Line}/** <summary>Chart definition.</summary> */ public sealed class ChartDefinition:AggregateRoot{/** <summary>Title.</summary> */ public string Title{get;private set;}=string.Empty;/** <summary>Type.</summary> */ public ChartType Type{get;private set;}/** <summary>Datasource.</summary> */ public string DatasourceKey{get;private set;}=string.Empty;/** <summary>X field.</summary> */ public string XField{get;private set;}=string.Empty;/** <summary>Y field.</summary> */ public string? YField{get;private set;}/** <summary>Aggregation.</summary> */ public ChartAggregation Aggregation{get;private set;}/** <summary>Colors.</summary> */ public string ColorsJson{get;private set;}="[]";/** <summary>Filters.</summary> */ public string? FiltersJson{get;private set;}/** <summary>Order.</summary> */ public int LayoutOrder{get;private set;}/** <summary>Enabled.</summary> */ public bool IsEnabled{get;private set;}/** <summary>Created.</summary> */ public DateTime CreatedAtUtc{get;private set;}/** <summary>Updated.</summary> */ public DateTime UpdatedAtUtc{get;private set;}private ChartDefinition(){}private ChartDefinition(string title,ChartType type,string ds,string x,string? y,ChartAggregation a,string colors,string? filters,int order):base(Guid.NewGuid()){Title=title;Type=type;DatasourceKey=ds;XField=x;YField=y;Aggregation=a;ColorsJson=colors;FiltersJson=filters;LayoutOrder=order;IsEnabled=true;CreatedAtUtc=UpdatedAtUtc=DateTime.UtcNow;}/** <summary>Creates.</summary> */ public static Result<ChartDefinition>Create(string? title,ChartType type,string? ds,string? x,string? y,ChartAggregation a,string? colors,string? filters,int order){if(string.IsNullOrWhiteSpace(title)||string.IsNullOrWhiteSpace(ds)||string.IsNullOrWhiteSpace(x))return ChartErrors.Invalid;return new ChartDefinition(title.Trim(),type,ds.Trim(),x.Trim(),y?.Trim(),a,string.IsNullOrWhiteSpace(colors)?"[]":colors,filters,order);}/** <summary>Updates.</summary> */ public Result<ChartDefinition>Update(string? title,ChartType type,string? ds,string? x,string? y,ChartAggregation a,string? colors,string? filters,int order,bool enabled){if(string.IsNullOrWhiteSpace(title)||string.IsNullOrWhiteSpace(ds)||string.IsNullOrWhiteSpace(x))return ChartErrors.Invalid;Title=title.Trim();Type=type;DatasourceKey=ds.Trim();XField=x.Trim();YField=y?.Trim();Aggregation=a;ColorsJson=string.IsNullOrWhiteSpace(colors)?"[]":colors;FiltersJson=filters;LayoutOrder=order;IsEnabled=enabled;UpdatedAtUtc=DateTime.UtcNow;return this;}}
/** <summary>Errors.</summary> */ public static class ChartErrors{/** <summary>Invalid.</summary> */ public static readonly Error Invalid=Error.Validation("dashboard.chart_invalid","Chart definition is invalid.");/** <summary>Not found.</summary> */ public static Error NotFound(Guid id)=>Error.NotFound("dashboard.chart_not_found",$"Chart '{id}' was not found.");/** <summary>Datasource missing.</summary> */ public static Error DatasourceNotFound(string key)=>Error.NotFound("dashboard.datasource_not_found",$"Datasource '{key}' was not found.");}
/** <summary>Repository.</summary> */ public interface IChartDefinitionRepository{/** <summary>Gets.</summary> */ Task<ChartDefinition?>GetAsync(Guid id,CancellationToken ct);/** <summary>Lists.</summary> */ Task<IReadOnlyList<ChartDefinition>>ListAsync(CancellationToken ct);/** <summary>Adds.</summary> */ void Add(ChartDefinition d);/** <summary>Removes.</summary> */ void Remove(ChartDefinition d);/** <summary>Saves.</summary> */ Task SaveAsync(CancellationToken ct);}
